mapper.sql:
SELECT t.ID, t.SHIPVOYAGE_ID, t.SHIPVOYAGE_ITEM_ID, t.SCN, t.SHIP_NAME, t.CARGO_INFO_NO, t.CARGO_OWNER_ID, t.CARGO_OWNER_NAME, t.CARGO_AGENT_ID, t.CARGO_AGENT_NAME, t.CARGO_CODE, t.CARGO_NAME, t.TRADE_TYPE, t.PACKING_CODE, t.PACKING_NAME, t.COMPANY_ID, t.COMPANY_NAME, t.PARENT_ID, t.ROOT_ID, t.QUANTITY, t.TON, t.RIGHTS_QUANTITY, t.SURPLUS_RIGHTS_QUANTITY, t.IS_CLEAR, t.CLEAR_BY, t.CLEAR_BY_NAME, t.CLEAR_DATE, t.CREATE_BY, t.CREATE_BY_NAME, t.CREATE_TIME, t.UPDATE_BY, t.UPDATE_BY_NAME, t.UPDATE_TIME, t.CONTRACT_CODE, t.VOYAGE, m.TALLY, t.RESIDUE_STORAGE, t.TRANSFER_DATE, CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TEMP."shipNameVoyage" || ',') ORDER BY TEMP."shipNameVoyage") AS CLOB), ','), '([^,]+)(,\1)+', '\1')) ELSE TO_CHAR(CASE WHEN t.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE t.SHIP_NAME || '_' || TDSI.VOYAGE END) END "shipNameVoyage", m.WORK_TYPE, t.IS_HQ FROM T_BUS_CARGO_INFO t LEFT JOIN M_CARGO m ON t.CARGO_CODE = m.CARGO_CODE LEFT JOIN T_BUS_TRUST TBT ON t.TRUST_ID = TBT.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON t.SHIPVOYAGE_ITEM_ID = TDSI.ID LEFT JOIN (SELECT TBTC.ID, TBTC.CARGO_INFO_ID, TBT2.SHIPVOYAGE_ITEM_ID, CASE WHEN TBT2.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE TBT2.SHIP_NAME || '_' || TDSI2.VOYAGE END "shipNameVoyage" FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT2 ON TBTC.TRUST_ID = TBT2.ID AND TBT2.TYPE = '装船' LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI2 ON TBT2.SHIPVOYAGE_ITEM_ID = TDSI2.ID GROUP BY TBTC.ID, TBTC.CARGO_INFO_ID, TBT2.SHIPVOYAGE_ITEM_ID, TBT2.SHIP_NAME, TDSI2.VOYAGE ) TEMP ON t.ID = TEMP.CARGO_INFO_ID
AND CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TEMP.SHIPVOYAGE_ITEM_ID ELSE t.SHIPVOYAGE_ITEM_ID END = #{shipvoyageItemId}
and t.SHIPVOYAGE_ID = #{shipvoyageId}
and t.SCN = #{scn}
and t.CARGO_INFO_NO LIKE #{cargoInfoNo_like}
and t.CONTRACT_CODE LIKE #{contractCode_like}
and t.CARGO_OWNER_ID = #{cargoOwnerId}
and t.CARGO_OWNER_NAME = #{cargoOwnerName}
and t.CARGO_AGENT_ID = #{cargoAgentId}
and t.CARGO_AGENT_NAME = #{cargoAgentName}
and t.CARGO_CODE = #{cargoCode}
and t.CARGO_NAME LIKE #{cargoNameLike,jdbcType=VARCHAR}
and t.TRADE_TYPE = #{tradeType}
and t.PACKING_CODE = #{packingCode}
and t.PACKING_NAME = #{packingName}
and t.COMPANY_ID = #{companyId}
and t.COMPANY_NAME = #{companyName}
and t.PARENT_ID = #{parentId}
and t.ROOT_ID = #{rootId}
and t.IS_CLEAR = #{isClear} OR IS_CLEAR IS NULL
and m.WORK_TYPE = #{workType,jdbcType=VARCHAR}
GROUP BY t.ID, t.SHIPVOYAGE_ID, t.SHIPVOYAGE_ITEM_ID, t.SCN, t.SHIP_NAME, t.CARGO_INFO_NO, t.CARGO_OWNER_ID, t.CARGO_OWNER_NAME, t.CARGO_AGENT_ID, t.CARGO_AGENT_NAME, t.CARGO_CODE, t.CARGO_NAME, t.TRADE_TYPE, t.PACKING_CODE, t.PACKING_NAME, t.COMPANY_ID, t.COMPANY_NAME, t.PARENT_ID, t.ROOT_ID, t.QUANTITY, t.TON, t.RIGHTS_QUANTITY, t.SURPLUS_RIGHTS_QUANTITY, t.IS_CLEAR, t.CLEAR_BY, t.CLEAR_BY_NAME, t.CLEAR_DATE, t.CREATE_BY, t.CREATE_BY_NAME, t.CREATE_TIME, t.UPDATE_BY, t.UPDATE_BY_NAME, t.UPDATE_TIME, t.CONTRACT_CODE, t.VOYAGE, m.TALLY, TBT.TYPE, t.SHIPVOYAGE_ITEM_ID, t.SHIP_NAME, t.RESIDUE_STORAGE, t.TRANSFER_DATE, TDSI.VOYAGE, m.WORK_TYPE, t.IS_HQ ORDER BY CREATE_TIME DESC

mapper.select:
WITH SOURCE AS ( SELECT TBCI.ID, CASE WHEN TBCI.SOURCE = '30' THEN '货转' WHEN TBCI.SOURCE = '50' THEN '混配' WHEN TBCI.SOURCE = '20' THEN '集港' WHEN tbci.SOURCE = '10' THEN '卸船' ELSE COALESCE(TBCI.IS_TOS, CASE WHEN TBT.TYPE = '拆箱集港' THEN '集港' ELSE TBT.TYPE END) END "source" FROM T_BUS_CARGO_INFO TBCI LEFT JOIN T_BUS_TRUST TBT ON TBCI.TRUST_ID = TBT.ID), STORAGE_RATE AS ( SELECT TBCC.COMPANY_ID, TBC.CUSTOMER_ID, TBC.START_TIME, TBC.END_TIME, TBCR.CARGO_CODE, TBCR.FREE_STORAGE_DAYS FROM T_BUS_CONTRACT_COMPANY TBCC JOIN T_BUS_CONTRACT TBC ON (TBC.STATUS = '20' AND TBCC.CONTRACT_ID = TBC.ID) JOIN T_BUS_CONTRACT_RATE TBCR ON (TBCR.TYPE = '10' AND TBCR.RATE_ITEM_CODE = 'MS00240' AND TBC.ID = TBCR.CONTRACT_ID) GROUP BY TBCC.COMPANY_ID, TBC.CUSTOMER_ID, TBC.START_TIME, TBC.END_TIME, TBCR.CARGO_CODE, TBCR.FREE_STORAGE_DAYS ORDER BY TBCR.FREE_STORAGE_DAYS DESC) SELECT CASE WHEN TEMP_TABLE.STATEMENT_STATUS = '30' THEN -999 WHEN TEMP_TABLE.IS_CLEAR = '0' AND "overdueDays" <=0 THEN -888 WHEN TEMP_TABLE.IS_CLEAR = '1' AND "overdueDays" <=0 THEN -777 WHEN TEMP_TABLE.IS_CLEAR = '0' AND "overdueDays" >0 THEN -666 WHEN TEMP_TABLE.IS_CLEAR = '1' AND "overdueDays" >0 THEN -555 ELSE -900 END ORDER_NUM, TEMP_TABLE.* FROM ( SELECT t.ID, t.SHIPVOYAGE_ID, t.SHIPVOYAGE_ITEM_ID, t.SCN, t.SHIP_NAME, t.CARGO_INFO_NO, t.CARGO_OWNER_ID, t.CARGO_OWNER_NAME, t.CARGO_AGENT_ID, t.CARGO_AGENT_NAME, t.CARGO_CODE, t.CARGO_NAME, t.TRADE_TYPE, t.PACKING_CODE, t.PACKING_NAME, t.COMPANY_ID, t.COMPANY_NAME, t.PARENT_ID, t.ROOT_ID, t.QUANTITY, t.TON, t.RIGHTS_QUANTITY, t.SURPLUS_RIGHTS_QUANTITY, t.IS_CLEAR, t.CLEAR_BY, t.CLEAR_BY_NAME, t.CLEAR_DATE, t.CREATE_BY, t.CREATE_BY_NAME, t.CREATE_TIME, t.UPDATE_BY, t.UPDATE_BY_NAME, t.UPDATE_TIME, t.CONTRACT_CODE, t.VOYAGE, t.RESIDUE_STORAGE, t.TRANSFER_DATE, m.TALLY, CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TEMP."shipNameVoyage" || ',') ORDER BY TEMP."shipNameVoyage") AS CLOB), ','), '([^,]+)(,\1)+', '\1')) ELSE TO_CHAR(CASE WHEN t.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE t.SHIP_NAME || '_' || TDSI.VOYAGE END) END "shipNameVoyage", CASE WHEN t.IS_TOS IS NOT NULL THEN t.IS_TOS ELSE TBT.TYPE END "type", m.WORK_TYPE, t.IS_LOGOUT, t.LOGOUT_BY_NAME, t.LOGOUT_BY, t.LOGOUT_TIME, t.REAL_CLEAR_DATE, NVL(tppss.balancePortStorageTon,0) balancePortStorageTon, t.IMP_EXP, decode(t.IS_PRE_PAY,'10','未预缴','20','部分预缴','30','已预缴') PRE_PAY_STATUS, TRUNC(NVL( t.REAL_CLEAR_DATE, SYSDATE) - CASE SOURCE."source" WHEN '卸船' THEN TDSI.WORK_START_TIME WHEN '集港' THEN WEIGH_JG."minWeighOutDt" WHEN '货转' THEN t.TRANSFER_DATE WHEN '混配' THEN TBCMR.MIX_TIME END - CASE SOURCE."source" WHEN '货转' THEN t.RESIDUE_STORAGE WHEN '混配' THEN t.MIX_FREE_STORAGE_DAYS WHEN '货转' THEN t.RESIDUE_STORAGE WHEN '混配' THEN t.MIX_FREE_STORAGE_DAYS END , 0) "overdueDays", t.STATEMENT_STATUS_CODE STATEMENT_STATUS, t.IS_HQ FROM T_BUS_CARGO_INFO t LEFT JOIN STORAGE_RATE ON (t.COMPANY_ID = STORAGE_RATE.COMPANY_ID AND t.CARGO_OWNER_ID = STORAGE_RATE.CUSTOMER_ID AND t.CARGO_CODE = STORAGE_RATE.CARGO_CODE) LEFT JOIN SOURCE ON (t.ID = SOURCE.ID AND SOURCE."source" IN ('卸船', '集港', '货转', '混配')) LEFT JOIN T_BUS_CARGO_MIX_RECORD TBCMR ON t.ID = TBCMR.CARGO_INFO_ID LEFT JOIN ( SELECT TEMP.CARGO_INFO_ID, MIN(TEMP.WEIGH_OUT_DT) "minWeighOutDt" FROM ( SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM ( SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港')) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER(VWI2.CARGO_INFO_ID), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE IN ('集港', '拆箱集港')) TEMP GROUP BY TEMP.CARGO_INFO_ID ) WEIGH_JG ON t.ID = WEIGH_JG.CARGO_INFO_ID LEFT JOIN M_CARGO m ON t.CARGO_CODE = m.CARGO_CODE LEFT JOIN T_BUS_TRUST TBT ON t.TRUST_ID = TBT.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON t.SHIPVOYAGE_ITEM_ID = TDSI.ID LEFT JOIN T_FD_BANK_CUSTOMER_PREPAYMENT TFBCP ON TFBCP.STATUS = '1' AND TFBCP.BUS_TRUST_ID = t.TRUST_ID LEFT JOIN (SELECT TBTC.ID, TBTC.CARGO_INFO_ID, TBT2.SHIPVOYAGE_ITEM_ID, CASE WHEN TBT2.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE TBT2.SHIP_NAME || '_' || TDSI2.VOYAGE END "shipNameVoyage" FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT2 ON TBTC.TRUST_ID = TBT2.ID AND TBT2.TYPE = '装船' LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI2 ON TBT2.SHIPVOYAGE_ITEM_ID = TDSI2.ID GROUP BY TBTC.ID, TBTC.CARGO_INFO_ID, TBT2.SHIPVOYAGE_ITEM_ID, TBT2.SHIP_NAME, TDSI2.VOYAGE ) TEMP ON t.ID = TEMP.CARGO_INFO_ID LEFT JOIN T_BUS_TRUST_CARGO TBTC ON t.ID = TBTC.CARGO_INFO_ID LEFT JOIN T_BUS_TRUST TBT2 ON TBTC.TRUST_ID = TBT2.ID LEFT JOIN ( SELECT CARGO_INFO_ID, sum( ton ) balancePortStorageTon FROM T_PRD_PORT_STORAGE TPPS WHERE TPPS.CLEAN_MASS_SIGN = '0' GROUP BY CARGO_INFO_ID ) tppss ON tppss.CARGO_INFO_ID = t.id
AND CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TEMP.SHIPVOYAGE_ITEM_ID ELSE t.SHIPVOYAGE_ITEM_ID END = #{shipvoyageItemId}
and t.SHIPVOYAGE_ID = #{shipvoyageId}
and t.SCN = #{scn}
and (t.IS_LOGOUT = #{isLogout} or t.IS_LOGOUT is null)
and TBTC.BUSINESS_NO LIKE #{businessNoLike}
and t.CARGO_INFO_NO LIKE #{cargoInfoNo_like}
and t.CONTRACT_CODE LIKE #{contractCode_like}
and t.CARGO_OWNER_ID = #{cargoOwnerId}
and t.CARGO_OWNER_NAME = #{cargoOwnerName}
and t.CARGO_AGENT_ID = #{cargoAgentId}
and t.CARGO_AGENT_NAME = #{cargoAgentName}
and t.CARGO_CODE = #{cargoCode}
and t.CARGO_NAME LIKE #{cargoNameLike,jdbcType=VARCHAR}
and t.TRADE_TYPE = #{tradeType}
and t.PACKING_CODE = #{packingCode}
and t.PACKING_NAME = #{packingName}
and t.COMPANY_ID = #{companyId}
and t.COMPANY_NAME = #{companyName}
and t.PARENT_ID = #{parentId}
and t.ROOT_ID = #{rootId}
and t.IS_CLEAR = #{isClear} OR IS_CLEAR IS NULL
and m.WORK_TYPE = #{workType,jdbcType=VARCHAR}
and to_char(t.CREATE_TIME,'YYYY-MM-DD') >= #{startDate,jdbcType=VARCHAR}
and to_char(t.CREATE_TIME,'YYYY-MM-DD') < #{endDate,jdbcType=VARCHAR}
GROUP BY SOURCE."source", WEIGH_JG."minWeighOutDt", t.TRANSFER_DATE, TBCMR.MIX_TIME, t.MIX_FREE_STORAGE_DAYS, t.STATEMENT_STATUS_CODE, t.IS_HQ, t.RESIDUE_STORAGE, t.REAL_CLEAR_DATE, TDSI.WORK_START_TIME, t.ID, t.SHIPVOYAGE_ID, t.SHIPVOYAGE_ITEM_ID, t.SCN, t.SHIP_NAME, t.CARGO_INFO_NO, t.CARGO_OWNER_ID, t.CARGO_OWNER_NAME, t.CARGO_AGENT_ID, t.CARGO_AGENT_NAME, t.CARGO_CODE, t.CARGO_NAME, t.TRADE_TYPE, t.PACKING_CODE, t.PACKING_NAME, t.COMPANY_ID, t.COMPANY_NAME, t.PARENT_ID, t.ROOT_ID, t.QUANTITY, t.TON, t.RIGHTS_QUANTITY, t.SURPLUS_RIGHTS_QUANTITY, t.IS_CLEAR, t.CLEAR_BY, t.CLEAR_BY_NAME, t.CLEAR_DATE, t.CREATE_BY, t.CREATE_BY_NAME, t.CREATE_TIME, t.UPDATE_BY, t.UPDATE_BY_NAME, t.UPDATE_TIME, t.CONTRACT_CODE, t.VOYAGE, t.RESIDUE_STORAGE, t.TRANSFER_DATE, m.TALLY, TBT.TYPE, t.SHIPVOYAGE_ITEM_ID, t.SHIP_NAME, TDSI.VOYAGE, t.IS_TOS, m.WORK_TYPE, t.IS_LOGOUT, t.LOGOUT_BY_NAME, t.LOGOUT_BY, t.LOGOUT_TIME, t.REAL_CLEAR_DATE, tppss.balancePortStorageTon, t.IMP_EXP, t.IS_PRE_PAY
HAVING CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TEMP."shipNameVoyage" || ',') ORDER BY TEMP."shipNameVoyage") AS CLOB), ','), '([^,]+)(,\1)+', '\1')) ELSE TO_CHAR(CASE WHEN t.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE t.SHIP_NAME || '_' || TDSI.VOYAGE END) END LIKE #{shipName_like}
AND CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TEMP."shipNameVoyage" || ',') ORDER BY TEMP."shipNameVoyage") AS CLOB), ','), '([^,]+)(,\1)+', '\1')) ELSE TO_CHAR(CASE WHEN t.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE t.SHIP_NAME || '_' || TDSI.VOYAGE END) END LIKE #{voyage_like}
HAVING CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TEMP."shipNameVoyage" || ',') ORDER BY TEMP."shipNameVoyage") AS CLOB), ','), '([^,]+)(,\1)+', '\1')) ELSE TO_CHAR(CASE WHEN t.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE t.SHIP_NAME || '_' || TDSI.VOYAGE END) END LIKE #{voyage_like}
ORDER BY CREATE_TIME DESC ) TEMP_TABLE order by ORDER_NUM DESC NULLS LAST

SELECT t.ID, t.SHIPVOYAGE_ID, t.SHIPVOYAGE_ITEM_ID, t.SCN, t.SHIP_NAME, t.CARGO_INFO_NO, t.CARGO_OWNER_ID, t.CARGO_OWNER_NAME, t.CARGO_AGENT_ID, t.CARGO_AGENT_NAME, t.CARGO_CODE, t.CARGO_NAME, t.TRADE_TYPE, t.PACKING_CODE, t.PACKING_NAME, t.COMPANY_ID, t.COMPANY_NAME, t.PARENT_ID, t.ROOT_ID, t.QUANTITY, t.TON, t.RIGHTS_QUANTITY, t.SURPLUS_RIGHTS_QUANTITY, t.IS_CLEAR, CASE WHEN t.IS_CLEAR = '1' THEN '是' ELSE '否' END "isClearLabel", t.CLEAR_BY, t.CLEAR_BY_NAME, t.CLEAR_DATE, t.CREATE_BY, t.CREATE_BY_NAME, t.CREATE_TIME, t.UPDATE_BY, t.UPDATE_BY_NAME, t.UPDATE_TIME, t.CONTRACT_CODE, t.VOYAGE, t.RESIDUE_STORAGE, t.TRANSFER_DATE, m.TALLY, REGEXP_REPLACE( LISTAGG(DECODE(TFBCP.STATUS, '1', '正常', '2', '作废', ''), ',') WITHIN GROUP ( ORDER BY TFBCP.STATUS ), '([^,]+)(,\1)+', '\1') "prePayStatus", REGEXP_REPLACE(LISTAGG(TFBCP.PREPAYMENT_CODE, ',') WITHIN GROUP ( ORDER BY TFBCP.PREPAYMENT_CODE ), '([^,]+)(,\1)+', '\1') "prePayNo", CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TO_CHAR(REGEXP_REPLACE(RTRIM(XMLCAST(XMLAGG(XMLELEMENT(E, TEMP."shipNameVoyage" || ',') ORDER BY TEMP."shipNameVoyage") AS CLOB), ','), '([^,]+)(,\1)+', '\1')) ELSE TO_CHAR(CASE WHEN t.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE t.SHIP_NAME || '_' || TDSI.VOYAGE END) END "shipNameVoyage", CASE WHEN t.IS_TOS IS NOT NULL THEN t.IS_TOS ELSE TBT.TYPE END "type", m.WORK_TYPE FROM T_BUS_CARGO_INFO t LEFT JOIN M_CARGO m ON t.CARGO_CODE = m.CARGO_CODE LEFT JOIN T_BUS_TRUST TBT ON t.TRUST_ID = TBT.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON t.SHIPVOYAGE_ITEM_ID = TDSI.ID LEFT JOIN T_FD_BANK_CUSTOMER_PREPAYMENT TFBCP ON TFBCP.STATUS = '1' AND TFBCP.BUS_TRUST_ID = t.TRUST_ID LEFT JOIN (SELECT TBTC.ID, TBTC.CARGO_INFO_ID, TBT2.SHIPVOYAGE_ITEM_ID, CASE WHEN TBT2.SHIPVOYAGE_ITEM_ID IS NULL THEN NULL ELSE TBT2.SHIP_NAME || '_' || TDSI2.VOYAGE END "shipNameVoyage" FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT2 ON TBTC.TRUST_ID = TBT2.ID AND TBT2.TYPE = '装船' LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI2 ON TBT2.SHIPVOYAGE_ITEM_ID = TDSI2.ID GROUP BY TBTC.ID, TBTC.CARGO_INFO_ID, TBT2.SHIPVOYAGE_ITEM_ID, TBT2.SHIP_NAME, TDSI2.VOYAGE ) TEMP ON t.ID = TEMP.CARGO_INFO_ID
AND CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TEMP.SHIPVOYAGE_ITEM_ID ELSE t.SHIPVOYAGE_ITEM_ID END = #{shipvoyageItemId}
and t.SHIPVOYAGE_ID = #{shipvoyageId}
and t.SCN = #{scn}
and t.CARGO_INFO_NO LIKE #{cargoInfoNo_like}
and t.CONTRACT_CODE LIKE #{contractCode_like}
and t.CARGO_OWNER_ID = #{cargoOwnerId}
and t.CARGO_OWNER_NAME = #{cargoOwnerName}
and t.CARGO_AGENT_ID = #{cargoAgentId}
and t.CARGO_AGENT_NAME = #{cargoAgentName}
and t.CARGO_CODE = #{cargoCode}
and t.CARGO_NAME LIKE #{cargoNameLike,jdbcType=VARCHAR}
and t.TRADE_TYPE = #{tradeType}
and t.PACKING_CODE = #{packingCode}
and t.PACKING_NAME = #{packingName}
and t.COMPANY_ID = #{companyId}
and t.COMPANY_NAME = #{companyName}
and t.PARENT_ID = #{parentId}
and t.ROOT_ID = #{rootId}
and t.IS_CLEAR = #{isClear} OR IS_CLEAR IS NULL
and m.WORK_TYPE = #{workType,jdbcType=VARCHAR}
GROUP BY t.ID, t.SHIPVOYAGE_ID, t.SHIPVOYAGE_ITEM_ID, t.SCN, t.SHIP_NAME, t.CARGO_INFO_NO, t.CARGO_OWNER_ID, t.CARGO_OWNER_NAME, t.CARGO_AGENT_ID, t.CARGO_AGENT_NAME, t.CARGO_CODE, t.CARGO_NAME, t.TRADE_TYPE, t.PACKING_CODE, t.PACKING_NAME, t.COMPANY_ID, t.COMPANY_NAME, t.PARENT_ID, t.ROOT_ID, t.QUANTITY, t.TON, t.RIGHTS_QUANTITY, t.SURPLUS_RIGHTS_QUANTITY, t.IS_CLEAR, t.CLEAR_BY, t.CLEAR_BY_NAME, t.CLEAR_DATE, t.CREATE_BY, t.CREATE_BY_NAME, t.CREATE_TIME, t.UPDATE_BY, t.UPDATE_BY_NAME, t.UPDATE_TIME, t.CONTRACT_CODE, t.VOYAGE, t.RESIDUE_STORAGE, t.TRANSFER_DATE, m.TALLY, TBT.TYPE, t.SHIPVOYAGE_ITEM_ID, t.SHIP_NAME, TDSI.VOYAGE, t.IS_TOS, m.WORK_TYPE ORDER BY CREATE_TIME DESC

SELECT TBCI.ID "id", SUM(TEMP.TRUST_CARGO_TON) "trustCargoTon" FROM T_BUS_CARGO_INFO TBCI JOIN (SELECT TBTC.CARGO_INFO_ID, TBTC.TON TRUST_CARGO_TON FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港','拆箱集港','疏港') ) TEMP ON TBCI.ID = TEMP.CARGO_INFO_ID WHERE TBCI.ID IN
#{id, jdbcType=BIGINT}
GROUP BY TBCI.ID

SELECT TBCI.ID "id", SUM(TEMP.TRUST_CARGO_TON) "trustCargoTon" FROM T_BUS_CARGO_INFO TBCI JOIN (SELECT TBTC.CARGO_INFO_ID, TBTC.TON TRUST_CARGO_TON FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港','拆箱集港') ) TEMP ON TBCI.ID = TEMP.CARGO_INFO_ID WHERE TBCI.ID IN
#{id, jdbcType=BIGINT}
GROUP BY TBCI.ID

SELECT TBCI.ID "id", SUM(TEMP.TRUST_CARGO_TON) "trustCargoTon" FROM T_BUS_CARGO_INFO TBCI JOIN (SELECT TBTC.CARGO_INFO_ID, TBTC.TON TRUST_CARGO_TON FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('疏港') ) TEMP ON TBCI.ID = TEMP.CARGO_INFO_ID WHERE TBCI.ID IN
#{id, jdbcType=BIGINT}
GROUP BY TBCI.ID

SELECT TBCI.ID "id", TBT.CREATE_BY_NAME "releaseByName", TO_CHAR(TBT.CREATE_TIME, 'YYYY-MM-DD HH24:MI:SS') "releaseTime" FROM T_BUS_CARGO_INFO TBCI JOIN T_BUS_TRUST_CARGO TBTC ON TBCI.ID = TBTC.CARGO_INFO_ID JOIN T_BUS_TRUST TBT ON (TBTC.TRUST_ID = TBT.ID AND TBCI.TRUST_ID != TBT.ID) WHERE TBCI.ID IN
#{id, jdbcType=BIGINT}
ORDER BY TBCI.ID, TBT.ID, TBT.CREATE_TIME

with TMP577 as (SELECT VWI2.PLAN_TYPE, VWI2.CARGO_INFO_ID, SUM(VWI2.WEIGHT_GOODS) WEIGHT_GOODS FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' GROUP BY VWI2.CARGO_INFO_ID, VWI2.PLAN_TYPE ), TMP399 as (SELECT TBTC.CARGO_INFO_ID, SUM(TBTC.TON) TRUST_CARGO_TON,TBT.TYPE TYPE FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID group by TBTC.CARGO_INFO_ID,TBT.TYPE )
SELECT SUM(CASE WHEN (CASE WHEN t.IS_TOS IS NOT NULL THEN t.IS_TOS ELSE TBT.TYPE END) = '卸船' THEN TEMP6.TON ELSE TEMP2.TON END) "handoverlistTon", SUM(TEMP3.TRUST_CARGO_TON) "trustCargoTonJG", SUM(TEMP99.TRUST_CARGO_TON) "trustCargoTonSG", SUM( CASE WHEN TEMP5.WEIGHT_GOODS IS NULL THEN 0 ELSE TEMP5.WEIGHT_GOODS END + CASE WHEN TEMP4.WEIGHT_GOODS IS NULL THEN 0 ELSE TEMP4.WEIGHT_GOODS END) "weightGoodsJG", SUM( CASE WHEN TEMP88.WEIGHT_GOODS IS NULL THEN 0 ELSE TEMP88.WEIGHT_GOODS END + CASE WHEN TEMP77.WEIGHT_GOODS IS NULL THEN 0 ELSE TEMP77.WEIGHT_GOODS END) "weightGoodsSG", (CASE WHEN SUM(TEMP3.TRUST_CARGO_TON) IS NULL THEN 0 ELSE SUM(TEMP3.TRUST_CARGO_TON) END) - (CASE WHEN SUM( CASE WHEN TEMP5.WEIGHT_GOODS IS NULL THEN 0 ELSE TEMP5.WEIGHT_GOODS END + CASE WHEN TEMP4.WEIGHT_GOODS IS NULL THEN 0 ELSE TEMP4.WEIGHT_GOODS END) IS NULL THEN 0 ELSE SUM( CASE WHEN TEMP5.WEIGHT_GOODS IS NULL THEN 0 ELSE TEMP5.WEIGHT_GOODS END + CASE WHEN TEMP4.WEIGHT_GOODS IS NULL THEN 0 ELSE TEMP4.WEIGHT_GOODS END) END ) "balanceTonJG", (CASE WHEN SUM(TEMP99.TRUST_CARGO_TON) IS NULL THEN 0 ELSE SUM(TEMP99.TRUST_CARGO_TON) END) - (CASE WHEN SUM(CASE WHEN TEMP88.WEIGHT_GOODS IS NULL THEN 0 ELSE TEMP88.WEIGHT_GOODS END + CASE WHEN TEMP77.WEIGHT_GOODS IS NULL THEN 0 ELSE TEMP77.WEIGHT_GOODS END) IS NULL THEN 0 ELSE SUM(CASE WHEN TEMP88.WEIGHT_GOODS IS NULL THEN 0ELSE TEMP88.WEIGHT_GOODS END + CASE WHEN TEMP77.WEIGHT_GOODS IS NULL THEN 0 ELSE TEMP77.WEIGHT_GOODS END) END ) "balanceTonSG", SUM(CASE WHEN t.IS_CLEAR = '0' THEN tppss.balancePortStorageTon WHEN t.IS_CLEAR = '1' THEN 0 END ) "balancePortStorageTon" FROM T_BUS_CARGO_INFO t LEFT JOIN M_CARGO m ON t.CARGO_CODE = m.CARGO_CODE
LEFT JOIN T_BUS_TRUST_CARGO TBTC ON t.ID = TBTC.CARGO_INFO_ID
LEFT JOIN T_BUS_TRUST TBT ON t.TRUST_ID = TBT.ID LEFT JOIN (select CARGO_INFO_ID,sum(ton) balancePortStorageTon FROM T_PRD_PORT_STORAGE TPPS WHERE TPPS.CLEAN_MASS_SIGN = '0' GROUP BY CARGO_INFO_ID) tppss on tppss.CARGO_INFO_ID = t.id
LEFT JOIN (SELECT CARGO_INFO_ID, SUM(TON) TON FROM T_BUS_HANDOVERLIST GROUP BY CARGO_INFO_ID) TEMP2 ON t.ID = TEMP2.CARGO_INFO_ID LEFT JOIN (SELECT CARGO_INFO_ID, SUM(CASE WHEN LOAD_UNLOAD = '卸' THEN TON ELSE 0 END) TON FROM T_BUS_HANDOVERLIST GROUP BY CARGO_INFO_ID) TEMP6 ON t.ID = TEMP6.CARGO_INFO_ID
LEFT JOIN (SELECT TMP399.CARGO_INFO_ID, SUM(TMP399.TRUST_CARGO_TON) TRUST_CARGO_TON FROM TMP399 where TMP399.TYPE IN ('集港','拆箱集港') GROUP BY TMP399.CARGO_INFO_ID) TEMP3 ON t.ID = TEMP3.CARGO_INFO_ID LEFT JOIN (SELECT TMP399.CARGO_INFO_ID, SUM(TMP399.TRUST_CARGO_TON) TRUST_CARGO_TON FROM TMP399 where TMP399.TYPE = '疏港' GROUP BY TMP399.CARGO_INFO_ID) TEMP99 ON t.ID = TEMP99.CARGO_INFO_ID LEFT JOIN (SELECT TEMP.CARGO_INFO_ID, SUM(VWI.WEIGHT_GOODS) WEIGHT_GOODS FROM (SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港')) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO GROUP BY TEMP.CARGO_INFO_ID) TEMP4 ON t.ID = TEMP4.CARGO_INFO_ID LEFT JOIN (SELECT TEMP.CARGO_INFO_ID, SUM(VWI.WEIGHT_GOODS) WEIGHT_GOODS FROM (SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('疏港')) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO GROUP BY TEMP.CARGO_INFO_ID) TEMP88 ON t.ID = TEMP88.CARGO_INFO_ID LEFT JOIN (select tmp577.CARGO_INFO_ID,sum(tmp577.WEIGHT_GOODS) WEIGHT_GOODS FROM TMP577 where TMP577.PLAN_TYPE in ('集港' , '拆箱集港') group by TMP577.CARGO_INFO_ID ) TEMP5 ON t.ID = TEMP5.CARGO_INFO_ID LEFT JOIN(select TMP577.CARGO_INFO_ID,sum(TMP577.WEIGHT_GOODS) WEIGHT_GOODS FROM TMP577 where TMP577.PLAN_TYPE = '疏港' group by TMP577.CARGO_INFO_ID ) TEMP77 ON t.ID = TEMP77.CARGO_INFO_ID
AND CASE WHEN TBT.TYPE IN ('集港', '拆箱集港') THEN TEMP.SHIPVOYAGE_ITEM_ID ELSE t.SHIPVOYAGE_ITEM_ID END = #{shipvoyageItemId}
and t.SHIPVOYAGE_ID = #{shipvoyageId}
and t.SCN = #{scn}
and t.CARGO_INFO_NO LIKE #{cargoInfoNo_like}
and t.CONTRACT_CODE LIKE #{contractCode_like}
and t.CARGO_OWNER_ID = #{cargoOwnerId}
and t.CARGO_OWNER_NAME = #{cargoOwnerName}
and t.CARGO_AGENT_ID = #{cargoAgentId}
and t.CARGO_AGENT_NAME = #{cargoAgentName}
and TBTC.BUSINESS_NO LIKE #{businessNoLike}
and t.CARGO_CODE = #{cargoCode}
and t.CARGO_NAME LIKE #{cargoNameLike,jdbcType=VARCHAR}
and t.TRADE_TYPE = #{tradeType}
and t.PACKING_CODE = #{packingCode}
and t.PACKING_NAME = #{packingName}
and t.COMPANY_ID = #{companyId}
and t.COMPANY_NAME = #{companyName}
and t.PARENT_ID = #{parentId}
and t.ROOT_ID = #{rootId}
and t.IS_CLEAR = #{isClear} OR IS_CLEAR IS NULL
and m.WORK_TYPE = #{workType,jdbcType=VARCHAR}

SELECT NVL(SUM(QUANTITY),0)
FROM T_BUS_CARGO_INFO
WHERE PARENT_ID = #{parentId,jdbcType=BIGINT}

