SELECT #{item.id, jdbcType=BIGINT}, #{item.num, jdbcType=VARCHAR}, #{item.cargoInfoId, jdbcType=VARCHAR}, #{item.coilNum, jdbcType=VARCHAR}, #{item.ton, jdbcType=VARCHAR}, #{item.coilSize1, jdbcType=VARCHAR}, #{item.coilSize2, jdbcType=VARCHAR}, #{item.status, jdbcType=VARCHAR}, #{item.businessType, jdbcType=VARCHAR}, #{item.receiveAddress, jdbcType=VARCHAR}, #{item.loginUserId, jdbcType=BIGINT}, #{item.loginUserName, jdbcType=VARCHAR}, #{item.now} FROM DUAL
