mapper.select:
SELECT t.UNION_NO, t.WEIGH_IN_DT, t.WEIGH_OUT_DT, t.GOODS_NAME, t.COM_NAME, t.VOYAGE, t.TRUCK_PLATE, CASE translate( t2.TYPE USING NCHAR_CS ) WHEN translate( '装船' USING NCHAR_CS ) THEN translate( '倒运' USING NCHAR_CS ) WHEN translate( '卸船' USING NCHAR_CS ) THEN translate( '倒运' USING NCHAR_CS ) ELSE translate( t2.TYPE USING NCHAR_CS ) END PLAN_TYPE, t.IN_BANG_NO, t.OUT_BANG_NO, t.WEIGHT_ALL, t.WEIGHT_SELF, t.WEIGHT_GOODS, t.CONSIGNOR_NAME, t.CONSIGNEE_NAME, t.AGENT_NAME, t.INV_REM FROM V_WEIGHT_INFO t LEFT JOIN T_BUS_TRUST_CARGO t1 ON t.PLAN_NO = t1.BUSINESS_NO LEFT JOIN T_BUS_TRUST t2 ON t1.TRUST_ID = t2.ID WHERE t.IS_OLD = '否'
and t1.CARGO_INFO_ID = #{cargoInfoId}
AND t1.CARGO_INFO_ID IN
#{id, jdbcType=BIGINT}
and t.TRUCK_PLATE = #{truckPlate}
and t.COM_NAME = #{shipName}
and t.VOYAGE = #{voyage}
and t.UNION_NO = #{unionNo}
and t.PLAN_NO = #{planNo}
and t.WEIGH_IN_DT >= to_date(#{startTime}, 'yyyy-mm-dd hh24:mi:ss')
and to_date(#{endTime}, 'yyyy-mm-dd hh24:mi:ss') >= t.WEIGH_OUT_DT
UNION ALL SELECT UNION_NO, WEIGH_IN_DT, WEIGH_OUT_DT, GOODS_NAME, COM_NAME, VOYAGE, TRUCK_PLATE, SCN PLAN_TYPE, IN_BANG_NO, OUT_BANG_NO, WEIGHT_ALL, WEIGHT_SELF, WEIGHT_GOODS, CONSIGNOR_NAME, CONSIGNEE_NAME, AGENT_NAME, INV_REM FROM V_WEIGHT_INFO WHERE IS_OLD = '是'
and CARGO_INFO_ID = #{cargoInfoId}
AND CARGO_INFO_ID IN
#{id, jdbcType=BIGINT}
and TRUCK_PLATE = #{truckPlate}
and COM_NAME = #{shipName}
and VOYAGE = #{voyage}
and UNION_NO = #{unionNo}
and PLAN_NO = #{planNo}
and WEIGH_IN_DT >= to_date(#{startTime}, 'yyyy-mm-dd hh24:mi:ss')
and to_date(#{endTime}, 'yyyy-mm-dd hh24:mi:ss') >= WEIGH_OUT_DT

SELECT COUNT(*)
FROM T_BUS_CARGO_TRANSFER
WHERE CARGO_INFO_ID_SOURCE = #{cargoInfoId} or CARGO_INFO_ID_TARGET = #{cargoInfoId}

SELECT COUNT(*)
FROM T_BUS_CARGO_MIX_RECORD TBCMR LEFT JOIN T_BUS_CARGO_MIX_DETAIL TBCMD ON TBCMR.ID = TBCMD.MIX_RECORD_ID
WHERE TBCMR.CARGO_INFO_ID = #{cargoInfoId} OR TBCMD.CARGO_INFO_ID = #{cargoInfoId}

SELECT COUNT(*)
FROM T_PRD_PORT_STORAGE TPPS
WHERE TPPS.CLEAN_MASS_SIGN = '0' AND TPPS.CARGO_INFO_ID =#{cargoInfoId}

SELECT TDSI.WORK_END_TIME FROM T_BUS_CARGO_INFO  TBCI
LEFT JOIN T_DIS_SHIPVOYAGE_ITEM tdsi ON TDSI.id =TBCI.SHIPVOYAGE_ITEM_ID
WHERE TBCI.ID =#{cargoInfoId}

SELECT COUNT(0)  FROM T_YARD_TALLY_ITEM tyti
LEFT JOIN T_YARD_TALLY tyt ON tyti.TALLY_ID = tyt.ID
WHERE tyt.DEL_FLAG = 0 and CARGO_INFO_ID = #{cargoInfoId}

SELECT TBTC.CARGO_INFO_ID "key", LISTAGG( TO_CHAR(tbt.TRUST_NO), ', ') WITHIN GROUP (ORDER BY tbt.TRUST_NO) AS "value" FROM T_BUS_TRUST tbt LEFT JOIN T_BUS_TRUST_CARGO tbtc ON tbt.id = TBTC.TRUST_ID WHERE TBTC.CARGO_INFO_ID in
#{id}
GROUP BY TBTC.CARGO_INFO_ID

